previewCss:
.darma-loader-darma-custom-507 {color: var(--loader-color, #059669);
  --loader-secondary-color: var(--loader-secondary-color, #2dd4bf);
  --loader-bg: var(--loader-bg, #ffffff);
   width: 60px;
   height: 16px;
   display: flex;
   justify-content: space-between;
   animation: darma-loader-darma-custom-507-l3-0 2s infinite alternate;
}
.darma-loader-darma-custom-507:before, .darma-loader-darma-custom-507:after  {
  content: "";
   width: 16px;
   background: var(--loader-color, #059669);
   animation: darma-loader-darma-custom-507-l3-1 1s infinite alternate;
}
.darma-loader-darma-custom-507:after  {
  background: var(--loader-secondary-color, #2dd4bf);
   --s:-1;
}
@keyframes darma-loader-darma-custom-507-l3-0  {
  0%,40% {transform: rotate(0)}
80%,100% {transform: rotate(.5turn)}
}
@keyframes darma-loader-darma-custom-507-l3-1  {
  80%,100% {transform: translate(calc(var(--s,1)*14px))}
}

